BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "ClassRooms" (
	"class_id"	VARCHAR(10) NOT NULL UNIQUE,
	"identifier"	VARCHAR(255) NOT NULL,
	"short_identifier"	VARCHAR(255) NOT NULL,
	"section"	TEXT NOT NULL,
	"year_id"	VARCHAR(255) NOT NULL,
	"option_id"	VARCHAR(255),
	"school_id"	VARCHAR(255) NOT NULL,
	"created_at"	DATETIME NOT NULL,
	"updated_at"	DATETIME NOT NULL,
	FOREIGN KEY("year_id") REFERENCES "StudyYears"("year_id") ON DELETE CASCADE ON UPDATE CASCADE,
	PRIMARY KEY("class_id"),
	FOREIGN KEY("school_id") REFERENCES "Schools"("school_id") ON DELETE CASCADE ON UPDATE CASCADE,
	FOREIGN KEY("option_id") REFERENCES "Options"("option_id") ON DELETE SET NULL ON UPDATE CASCADE
);
CREATE TABLE IF NOT EXISTS "Users" (
	"user_id"	VARCHAR(10) NOT NULL UNIQUE,
	"last_name"	VARCHAR(255) NOT NULL,
	"middle_name"	VARCHAR(255) NOT NULL,
	"first_name"	VARCHAR(255),
	"username"	VARCHAR(255) NOT NULL UNIQUE,
	"password"	VARCHAR(255) NOT NULL,
	"gender"	TEXT NOT NULL DEFAULT 'M',
	"role"	TEXT NOT NULL DEFAULT 'STUDENT',
	"birth_date"	DATE,
	"birth_place"	VARCHAR(255),
	"school_id"	VARCHAR(255) NOT NULL,
	"created_at"	DATETIME NOT NULL,
	"updated_at"	DATETIME NOT NULL,
	FOREIGN KEY("school_id") REFERENCES "Schools"("school_id") ON DELETE CASCADE ON UPDATE CASCADE,
	PRIMARY KEY("user_id")
);
CREATE TABLE IF NOT EXISTS "ClassroomEnrolements" (
	"enrolement_id"	VARCHAR(10) NOT NULL UNIQUE,
	"classroom_id"	VARCHAR(255) NOT NULL,
	"status"	TEXT NOT NULL DEFAULT 'EN_COURS',
	"is_new_student"	TINYINT(1) NOT NULL DEFAULT 0,
	"student_code"	VARCHAR(255) NOT NULL,
	"student_id"	VARCHAR(255) NOT NULL,
	"school_id"	VARCHAR(255) NOT NULL,
	"year_id"	VARCHAR(255) NOT NULL,
	"created_at"	DATETIME NOT NULL,
	"updated_at"	DATETIME NOT NULL,
	FOREIGN KEY("student_id") REFERENCES "Users"("user_id") ON DELETE CASCADE ON UPDATE CASCADE,
	PRIMARY KEY("enrolement_id"),
	FOREIGN KEY("classroom_id") REFERENCES "ClassRooms"("class_id") ON DELETE CASCADE ON UPDATE CASCADE,
	FOREIGN KEY("year_id") REFERENCES "StudyYears"("year_id") ON DELETE CASCADE ON UPDATE CASCADE,
	FOREIGN KEY("school_id") REFERENCES "Schools"("school_id") ON DELETE CASCADE ON UPDATE CASCADE
);
CREATE TABLE IF NOT EXISTS "ClassroomEnrolementActions" (
	"action_id"	VARCHAR(10) NOT NULL UNIQUE,
	"enrolement_id"	VARCHAR(255) NOT NULL,
	"reason"	VARCHAR(255),
	"action"	TEXT NOT NULL,
	"created_at"	DATETIME NOT NULL,
	"updated_at"	DATETIME NOT NULL,
	PRIMARY KEY("action_id"),
	FOREIGN KEY("enrolement_id") REFERENCES "ClassroomEnrolements"("enrolement_id") ON DELETE CASCADE ON UPDATE CASCADE
);
CREATE TABLE IF NOT EXISTS "Schools" (
	"school_id"	VARCHAR(10) NOT NULL UNIQUE,
	"name"	VARCHAR(255) NOT NULL,
	"adress"	VARCHAR(255) NOT NULL,
	"town"	VARCHAR(255) NOT NULL,
	"logo"	VARCHAR(255),
	"created_at"	DATETIME NOT NULL,
	"updated_at"	DATETIME NOT NULL,
	PRIMARY KEY("school_id")
);
CREATE TABLE IF NOT EXISTS "StudyYears" (
	"year_id"	VARCHAR(10) NOT NULL UNIQUE,
	"year_name"	VARCHAR(255) NOT NULL UNIQUE,
	"start_date"	DATETIME NOT NULL,
	"end_date"	DATETIME NOT NULL,
	"school_id"	VARCHAR(255) NOT NULL,
	"created_at"	DATETIME NOT NULL,
	"updated_at"	DATETIME NOT NULL,
	PRIMARY KEY("year_id"),
	FOREIGN KEY("school_id") REFERENCES "Schools"("school_id")
);
CREATE TABLE IF NOT EXISTS "Options" (
	"option_id"	VARCHAR(10) NOT NULL UNIQUE,
	"option_name"	VARCHAR(255) NOT NULL,
	"option_short_name"	VARCHAR(255) NOT NULL,
	"section"	TEXT NOT NULL DEFAULT 'SECONDARY',
	"school_id"	VARCHAR(255) NOT NULL,
	PRIMARY KEY("option_id"),
	FOREIGN KEY("school_id") REFERENCES "Schools"("school_id") ON DELETE CASCADE ON UPDATE CASCADE
);
COMMIT;
